4121 /// Reorders the given \p Order according to the given \p Mask. \p Order - is
4122 /// the original order of the scalars. Procedure transforms the provided order
4123 /// in accordance with the given \p Mask. If the resulting \p Order is just an
4124 /// identity order, \p Order is cleared.
4125 static void reorderOrder(SmallVectorImpl<unsigned> &Order, ArrayRef<int> Mask,
4126                          bool BottomOrder = false) {
4127   assert(!Mask.empty() && "Expected non-empty mask.");
4128   unsigned Sz = Mask.size();
4129   if (BottomOrder) {
4130     SmallVector<unsigned> PrevOrder;
4131     if (Order.empty()) {
4132       PrevOrder.resize(Sz);
4133       std::iota(PrevOrder.begin(), PrevOrder.end(), 0);
4134     } else {
4135       PrevOrder.swap(Order);
4136     }
4137     Order.assign(Sz, Sz);
4138     for (unsigned I = 0; I < Sz; ++I)
4139       if (Mask[I] != PoisonMaskElem)
4140         Order[I] = PrevOrder[Mask[I]];
